What is the output of the following code?

int a = 5;
cout << ++a << endl;

What will be the output of the following code?

int x = 10;
int &ref = x;
ref = 20;
cout << x << endl;

What will be the output of this code?

int a = 5, b = 10;
cout << (a > b ? a : b);

What will be the output of:

int a = 10;
a += 5;
cout << a;

What is the output of:

int x = 3;
cout << (x << 1);
